n// TEDARİKÇİ PORTALI - YENİ MODELLER\n// ==========================================\n\nenum TedarikciDurum {\n  BEKLIYOR\n  AKTIF\n  PASIF\n  REDDEDILDI\n}\n\nenum DavetDurum {\n  BEKLIYOR\n  KULLANILDI\n  IPTAL_EDILDI\n  SURESI_DOLDU\n}\n\nenum BelgeTuru {\n  VERGI_LEVHASI\n  ISO_BELGESI\n  IMZA_SIRKULERI\n  TICARET_SICIL\n  DIGER\n}\n\nmodel TedarikciDavet {\n  id                Int        @id @default(autoincrement())\n  email             String\n  firmaAdi          String?\n  kategoriler       Json?\n  token             String     @unique\n  davetEdenId       String\n  davetTarihi       DateTime   @default(now())\n  sonKullanmaTarihi DateTime\n  durum             DavetDurum @default(BEKLIYOR)\n  kullanilanTarih   DateTime?\n  davetEden         User       @relation(\"DavetGonderenUser\", fields: [davetEdenId], references: [id])\n}\n\nmodel TedarikciBelge {\n  id            Int       @id @default(autoincrement())\n  tedarikciId   Int\n  tur           BelgeTuru\n  dosyaAdi      String\n  dosyaUrl      String\n  yuklemeTarihi DateTime  @default(now())\n  tedarikci     Tedarikci @relation(fields: [tedarikciId], references: [id], onDelete: Cascade)\n}\n\nmodel TedarikciIban {\n  id          Int       @id @default(autoincrement())\n  tedarikciId Int\n  bankaAdi    String\n  iban        String\n  varsayilan  Boolean   @default(false)\n  tedarikci   Tedarikci @relation(fields: [tedarikciId], references: [id], onDelete: Cascade)\n}\n",
